<template>
  <div class="row g-3 mt-1 m-lg-1 mb-1">
    <div>
      <div class="row m-1">
        <input
          type="text"
          class="form-control col"
          id="title"
          placeholder="عنوان"
          v-model="watch.title"
          required
        />
        <label for="title" class="col">عنوان</label>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <select class="form-select col" id="stock" required v-if="stocks">
          <option>
            {{ stocks.symbol }}
          </option>
        </select>
        <label for="title" class="col">انتخاب سهم</label>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <select
          class="form-select col"
          id="stock"
          required
          v-model="watch.cond_variable"
        >
          <option value="last" selected>آخرین قیمت</option>
          <option value="close">قیمت بسته شدن</option>
          <option value="open">قیمت باز شدن</option>
          <option value="yesterday">قیمت دیروز</option>
          <option value="high">بالاترین قیمت</option>
          <option value="low">پایین ترین قیمت</option>
          <option value="count">تعداد سهم</option>
          <option value="volume">حجم</option>
          <option value="value">ارزش</option>
        </select>
        <label for="title" class="col">قیمت گذاری برای</label>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <select
          class="form-select col"
          id="stock"
          required
          v-model="watch.cond"
        >
          <option value="gr" selected>بیشتر یا مساوی</option>
          <option value="lt">کمتر یا مساوی</option>
        </select>
        <label for="title" class="col">شرط</label>
      </div>
    </div>
    <!--    seprate-->
    <div>
      <div class="row m-1">
        <input
          type="number"
          name="Last"
          class="col form-control m-1"
          v-model="watch.condition"
          min="0"
        />
        <label for="title" class="col">مقدار</label>
      </div>
    </div>
    <!--    seprate-->
    <div class="row m-1">
      <!--      <span class="col-4"></span>-->
      <button
        @click="add_new_stock"
        type="button"
        class="btn btn-outline-success col-3 m-3"
      >
        ثبت ویرایش
      </button>
      <button
        @click="delete_stock"
        type="button"
        class="btn btn-outline-danger col-3 m-3"
      >
        حذف از واچ لیست
      </button>
      <button
        @click="disable_stock"
        type="button"
        class="btn btn-outline-warning col-3 m-3"
        v-if="watch.enable"
      >
        غیر فعال کردن
      </button>
      <button
        @click="enable_stock"
        type="button"
        class="btn btn-outline-info col-3 m-3"
        v-if="!watch.enable"
      >
        فعال کردن
      </button>
    </div>
  </div>
</template>

<script>
import axios from "axios";

export default {
  name: "HomeView",
  components: {},
  data() {
    return {
      watch: {
        stock: 1,
        condition: 0,
        title: null,
        cond: "gr",
        enable: true,
        cond_variable: "last",
      },
      stocks: null,
    };
  },
  mounted() {
    axios
      .get(`${this.host}/api/onwatch/${this.$route.params.id}/`, {
        headers: { Authorization: `Bearer ${this.getCookie("token")}` },
      })
      .then((res) => {
        this.watch = res.data;
        axios.get(`${this.host}/api/stock/${res.data.stock}/`).then((stk) => {
          this.stocks = stk.data;
        });
      });
  },
  methods: {
    add_new_stock() {
      axios
        .patch(
          `${this.host}/api/onwatch/${this.$route.params.id}/`,
          this.watch,
          {
            headers: { Authorization: `Bearer ${this.getCookie("token")}` },
          }
        )
        .then(() => {
          window.alert("به واچ لیست شما اضافه شد");
          this.$router.push("/dashboard");
        });
    },
    disable_stock() {
      this.watch.enable = false;
      axios
        .patch(
          `${this.host}/api/onwatch/${this.$route.params.id}/`,
          this.watch,
          {
            headers: { Authorization: `Bearer ${this.getCookie("token")}` },
          }
        )
        .then(() => {
          window.alert("از واچ لیست شما غیر فعال شد");
          this.$router.push("/dashboard");
        });
    },
    delete_stock() {
      axios
        .delete(`${this.host}/api/onwatch/${this.$route.params.id}/`, {
          headers: { Authorization: `Bearer ${this.getCookie("token")}` },
        })
        .then(() => {
          window.alert("از واچ لیست شما حذف شد");
          this.$router.push("/dashboard");
        })
        .catch((err) => {
          console.log(err);
        });
    },
    enable_stock() {
      this.watch.enable = true;
      axios
        .patch(
          `${this.host}/api/onwatch/${this.$route.params.id}/`,
          this.watch,
          {
            headers: { Authorization: `Bearer ${this.getCookie("token")}` },
          }
        )
        .then(() => {
          window.alert("فعال شد");
          this.$router.push("/dashboard");
        })
        .catch((err) => {
          console.log(err);
        });
    },
    getCookie(name) {
      const cookies = document.cookie.split(";");
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim(); // Remove leading/trailing spaces
        if (cookie.startsWith(name + "=")) {
          return cookie.split("=")[1]; // Extract value
        }
      }
      return null; // Cookie not found
    },
  },
};
</script>

