<template>
  <div class="dashboard">
    <div class="row row-cols-1 row-cols-md-6 img-router">
      <router-link class="img-router" to="/new-cond">
        <div class="col">
          <div class="card">
            <img src="../assets/add.png" class="card-img-top" alt="..." />
            <div class="card-body">
              <h5 class="card-title">Add New Stock</h5>
              <p class="card-text">text</p>
            </div>
          </div>
        </div>
      </router-link>
      <router-link
        v-for="watch in onwatchs"
        :key="watch.id"
        :item="watch"
        :to="'/watch/' + watch.id"
        class="img-router"
      >
        <StockCmp :item="watch" />
      </router-link>
    </div>
  </div>
</template>

<script>
import StockCmp from "@/components/StockCmp.vue";
import axios from "axios";

export default {
  name: "HomeView",
  components: {
    StockCmp,
  },
  data() {
    return {
      onwatchs: null,
      stock_name: null,
    };
  },
  mounted() {
    axios
      .get(`${this.host}/api/onwatch/`, {
        headers: { Authorization: `Bearer ${this.getCookie("token")}` },
      })
      .then((res) => {
        this.onwatchs = res.data;
      });
  },
  methods: {
    getCookie(name) {
      const cookies = document.cookie.split(";");
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim(); // Remove leading/trailing spaces
        if (cookie.startsWith(name + "=")) {
          return cookie.split("=")[1]; // Extract value
        }
      }
      return null; // Cookie not found
    },
  },
};
</script>

