<template>
  <div class="container m-4 border p-4">
    <div class="row">
      <div class="col-3">
        <img src="../assets/telegram.png" />
      </div>
      <div class="col-9" v-if="auth_link">
        <a :href="auth_link">Connect To Telegram Service Notification</a>
      </div>
    </div>
  </div>
</template>

<script>
import axios from "axios";

export default {
  name: "HomeView",
  components: {
    // HelloWorld,
  },
  data() {
    return {
      token: this.getCookie("token"),
      auth_link: null,
      headers: { Authorization: `Bearer ${this.getCookie("token")}` },
    };
  },
  methods: {
    getCookie(name) {
      const cookies = document.cookie.split(";");
      for (let i = 0; i < cookies.length; i++) {
        const cookie = cookies[i].trim(); // Remove leading/trailing spaces
        if (cookie.startsWith(name + "=")) {
          return cookie.split("=")[1]; // Extract value
        }
      }
      return null; // Cookie not found
    },
  },
  mounted() {
    axios
      .get(`${this.host}/api/telath/`, { headers: this.headers })
      .then((ttk) => {
        this.auth_link = ttk.data.auth_link;
      });
  },
};
</script>

